const getRandomBocaCerrada = () => {
  return bocaCerradaChallenges[Math.floor(Math.random() * bocaCerradaChallenges.length)];
};
const formatBocaCerradaChallenge = (challenge, playerName) => {
  return `🤐 BOCA CERRADA

${playerName}, di esta frase/palabra CON LOS LABIOS CERRADOS:

"${challenge.text}"

¡Los demás tienen que adivinar!`;
};
function detectRarity(card) {
  const t2 = safeLower(card);
  if (t2.includes("impostor") || t2.includes("vampiro") || t2.includes("kamasutra") || t2.includes("confesionario") || t2.includes("polígrafo"))
    return "rare";
  if (t2.includes("virus"))
    return "virus";
  if (t2.includes("doble o nada") || t2.includes("a follar") || t2.includes("modo avión"))
    return "legendary";
  if (t2.includes("🧨") || t2.includes("💀") || t2.includes("destroyer"))
    return "chaos";
  return "common";
}
function pickWeighted(items, weights) {
  const total = weights.reduce((a2, b2) => a2 + b2, 0);
  let r2 = Math.random() * total;
  for (let i2 = 0; i2 < items.length; i2++) {
    r2 -= weights[i2];
    if (r2 <= 0)
      return items[i2];
  }
  return items[items.length - 1];
}
const useDrinkingMicroGames = (mode2, playersCount) => {
  const recentMiniRef = reactExports.useRef([]);
  const lastMiniTurnRef = reactExports.useRef({});
  const checkDrinkingGame = (currentIndex, currentPlayerName, setGameState) => {
    if (mode2 !== "megamix" && mode2 !== "clasico")
      return false;
    const triggerChance = mode2 === "megamix" ? 0.3 : 0.22;
    if (Math.random() > triggerChance)
      return false;
    const turn = currentIndex;
    const last = recentMiniRef.current[recentMiniRef.current.length - 1];
    const recently = new Set(recentMiniRef.current.slice(-6));
    const canUse = (type, cooldownTurns) => {
      const lastTurn = lastMiniTurnRef.current[type];
      if (typeof lastTurn === "number" && turn - lastTurn < cooldownTurns)
        return false;
      if (type === last)
        return false;
      if ((type === "boca" || type === "impostor_word") && recently.has(type))
        return false;
      return true;
    };
    const candidates = [
      {
        type: "cascada",
        weight: 0.9,
        ok: canUse("cascada", 8) && turn > 0 && turn % 5 === 0,
        run: () => {
          const cascade = getRandomCascade();
          const processed = {
            ...cascade,
            description: cascade.description.replace(/{player}/g, currentPlayerName)
          };
          setGameState((prev) => ({ ...prev, showDrinkingGame: true, currentDrinkingGame: processed }));
        }
      },
      {
        type: "coin",
        weight: 0.8,
        ok: canUse("coin", 10) && turn > 0 && turn % 7 === 0,
        run: () => {
          const coinGame = getRandomCoinGame();
          const processed = {
            ...coinGame,
            description: coinGame.description.replace(/{player}/g, currentPlayerName)
          };
          setGameState((prev) => ({ ...prev, showDrinkingGame: true, currentDrinkingGame: processed }));
        }
      },
      {
        type: "mimica",
        weight: 1.1,
        ok: canUse("mimica", 6),
        run: () => {
          const mimica = getRandomMimica();
          setGameState((prev) => ({
            ...prev,
            showMimica: false,
            // Don't show immediately
            showMimicaReveal: true,
            // Show handover first
            currentMimicaText: formatMimicaChallenge(mimica, currentPlayerName)
          }));
        }
      },
      {
        type: "drinking",
        weight: 1,
        ok: canUse("drinking", 4),
        run: () => {
          const drinkingGame = getRandomDrinkingGame();
          const processed = {
            ...drinkingGame,
            description: drinkingGame.description.replace(/{player}/g, currentPlayerName)
          };
          setGameState((prev) => ({ ...prev, showDrinkingGame: true, currentDrinkingGame: processed }));
        }
      },
      {
        type: "boca",
        weight: 0.55,
        ok: canUse("boca", 14),
        run: () => {
          const bocaCerrada = getRandomBocaCerrada();
          setGameState((prev) => ({
            ...prev,
            showBocaCerrada: false,
            // Don't show immediately
            showBocaCerradaReveal: true,
            // Show handover first
            currentBocaCerradaText: formatBocaCerradaChallenge(bocaCerrada, currentPlayerName)
          }));
        }
      },
      {
        type: "impostor_word",
        weight: 0.55,
        ok: canUse("impostor_word", 14),
        run: () => {
          const word = getRandomImpostorWord();
          setGameState((prev) => ({ ...prev, showImpostorWord: true, currentImpostorWord: word }));
        }
      }
    ];
    const eligibleCandidates = candidates.filter((c2) => c2.ok);
    if (eligibleCandidates.length === 0)
      return false;
    const picked = pickWeighted(eligibleCandidates, eligibleCandidates.map((c2) => c2.weight));
    picked.run();
    lastMiniTurnRef.current[picked.type] = turn;
    recentMiniRef.current = [...recentMiniRef.current, picked.type].slice(-20);
    return true;
  };
  return {
    checkDrinkingGame,
    lastMiniTurnRef
  };
};
